const observers = new Map();

export function initialize(sentinelElement, dotNetHelper) {
    if (observers.has(sentinelElement)) {
        return;
    }

    const observer = new IntersectionObserver(entries => {
        for (const entry of entries) {
            if (entry.isIntersecting) {
                dotNetHelper.invokeMethodAsync("OnSentinelVisible");
            }
        }
    }, { rootMargin: "0px 0px 250px 0px" });

    observer.observe(sentinelElement);
    observers.set(sentinelElement, observer);
}

export function dispose(sentinelElement) {
    const observer = observers.get(sentinelElement);
    if (observer) {
        observer.disconnect();
        observers.delete(sentinelElement);
    }
}

@typeparam TItem
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="sentinelRef" class="infinite-scroll-sentinel">
            @if (isLoading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    private ElementReference sentinelRef;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? dotNetRef;
    private bool isLoading;
    private bool isDisposed;

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./js/infiniteScroll.js");
        }

        if (jsModule is not null && HasMore)
        {
            await jsModule.InvokeVoidAsync("initialize", sentinelRef, dotNetRef);
        }
    }

    [JSInvokable]
    public async Task OnSentinelVisible()
    {
        if (isLoading || !HasMore || isDisposed)
        {
            return;
        }

        isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        isDisposed = true;

        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose", sentinelRef);
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit disconnected; safe to ignore.
            }
        }

        dotNetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem 0;
    min-height: 1px;
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to {
        transform: rotate(360deg);
    }
}

